namespace sv_7ab33c71045541e999d1f83ea1e56e67.Services;

public record UserProfile(string DisplayName, string Email, string AvatarUrl, string Bio);
public record NotificationPrefs(bool EmailNotifications, bool PushNotifications, bool WeeklyDigest, List<string> MutedChannels);
public record SecuritySettings(bool TwoFactorEnabled, DateTime? LastPasswordChange, List<ActiveSession> Sessions);
public record ActiveSession(string Id, string Device, string Location, DateTime LastActive);
public record AppearanceSettings(string Theme, string FontSize, string Language, bool CompactMode);

public interface ISettingsService
{
    Task<UserProfile> GetProfileAsync();
    Task SaveProfileAsync(UserProfile profile);
    Task<NotificationPrefs> GetNotificationPrefsAsync();
    Task SaveNotificationPrefsAsync(NotificationPrefs prefs);
    Task<SecuritySettings> GetSecuritySettingsAsync();
    Task ChangePasswordAsync(string currentPassword, string newPassword);
    Task RevokeSessionAsync(string sessionId);
    Task<AppearanceSettings> GetAppearanceAsync();
    Task SaveAppearanceAsync(AppearanceSettings settings);
}

@namespace sv_7ab33c71045541e999d1f83ea1e56e67.Components.Pages.Settings

<nav class="settings-sidebar">
    <ul class="nav nav-pills flex-column">
        @foreach (var section in Sections)
        {
            <li class="nav-item">
                <button class="nav-link w-100 text-start @(ActiveSection == section.Key ? "active" : "")"
                        @onclick="() => OnSectionChanged.InvokeAsync(section.Key)">
                    <span class="me-2">@section.Icon</span>
                    @section.Label
                </button>
            </li>
        }
    </ul>
</nav>

@code {
    [Parameter, EditorRequired] public string ActiveSection { get; set; } = "";
    [Parameter, EditorRequired] public EventCallback<string> OnSectionChanged { get; set; }

    private static readonly (string Key, string Label, string Icon)[] Sections =
    [
        ("profile", "Profile", "👤"),
        ("notifications", "Notifications", "🔔"),
        ("security", "Security", "🔒"),
        ("appearance", "Appearance", "🎨")
    ];
}

@namespace sv_7ab33c71045541e999d1f83ea1e56e67.Components.Pages.Settings
@using sv_7ab33c71045541e999d1f83ea1e56e67.Services
@inject ISettingsService SettingsService

@if (_loading)
{
    <div class="text-center py-5"><div class="spinner-border" role="status"></div></div>
}
else if (_profile is not null)
{
    <h4 class="mb-4">Profile Settings</h4>

    @if (_successMessage is not null)
    {
        <div class="alert alert-success alert-dismissible fade show" role="alert">
            @_successMessage
            <button type="button" class="btn-close" @onclick="() => _successMessage = null"></button>
        </div>
    }

    <div class="row">
        <div class="col-md-8">
            <div class="mb-3">
                <label class="form-label">Display Name</label>
                <input type="text" class="form-control" @bind="_displayName" />
            </div>
            <div class="mb-3">
                <label class="form-label">Email</label>
                <input type="email" class="form-control" @bind="_email" />
            </div>
            <div class="mb-3">
                <label class="form-label">Bio</label>
                <textarea class="form-control" rows="4" @bind="_bio"></textarea>
            </div>
        </div>
        <div class="col-md-4">
            <div class="text-center">
                <div class="avatar-preview mb-2">
                    @if (!string.IsNullOrWhiteSpace(_avatarUrl))
                    {
                        <img src="@_avatarUrl" alt="Avatar" class="rounded-circle img-fluid"
                             style="width:120px;height:120px;object-fit:cover;" />
                    }
                    else
                    {
                        <div class="rounded-circle bg-secondary d-flex align-items-center justify-content-center"
                             style="width:120px;height:120px;margin:0 auto;">
                            <span class="text-white fs-1">👤</span>
                        </div>
                    }
                </div>
                <small class="text-muted d-block text-break">@(_avatarUrl ?? "No avatar set")</small>
            </div>
        </div>
    </div>

    <div class="d-flex gap-2 mt-3">
        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
            @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
            Save Changes
        </button>
        <button class="btn btn-outline-secondary" @onclick="Discard" disabled="@_saving">
            Discard Changes
        </button>
    </div>
}

@code {
    private UserProfile? _profile;
    private string _displayName = "";
    private string _email = "";
    private string _bio = "";
    private string _avatarUrl = "";
    private bool _loading = true;
    private bool _saving;
    private string? _successMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadAsync();
    }

    private async Task LoadAsync()
    {
        _loading = true;
        _profile = await SettingsService.GetProfileAsync();
        PopulateFields(_profile);
        _loading = false;
    }

    private void PopulateFields(UserProfile p)
    {
        _displayName = p.DisplayName;
        _email = p.Email;
        _bio = p.Bio;
        _avatarUrl = p.AvatarUrl;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _successMessage = null;
        var updated = new UserProfile(_displayName, _email, _avatarUrl, _bio);
        await SettingsService.SaveProfileAsync(updated);
        _profile = updated;
        _successMessage = "Profile saved successfully!";
        _saving = false;
    }

    private void Discard()
    {
        if (_profile is not null)
        {
            PopulateFields(_profile);
            _successMessage = null;
        }
    }
}

@namespace sv_7ab33c71045541e999d1f83ea1e56e67.Components.Pages.Settings
@using sv_7ab33c71045541e999d1f83ea1e56e67.Services
@inject ISettingsService SettingsService

@if (_loading)
{
    <div class="text-center py-5"><div class="spinner-border" role="status"></div></div>
}
else
{
    <h4 class="mb-4">Notification Preferences</h4>

    @if (_successMessage is not null)
    {
        <div class="alert alert-success alert-dismissible fade show" role="alert">
            @_successMessage
            <button type="button" class="btn-close" @onclick="() => _successMessage = null"></button>
        </div>
    }

    <div class="mb-4">
        <div class="form-check form-switch mb-3">
            <input class="form-check-input" type="checkbox" id="emailNotif" @bind="_emailNotifications" />
            <label class="form-check-label" for="emailNotif">Email Notifications</label>
        </div>
        <div class="form-check form-switch mb-3">
            <input class="form-check-input" type="checkbox" id="pushNotif" @bind="_pushNotifications" />
            <label class="form-check-label" for="pushNotif">Push Notifications</label>
        </div>
        <div class="form-check form-switch mb-3">
            <input class="form-check-input" type="checkbox" id="weeklyDigest" @bind="_weeklyDigest" />
            <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
        </div>
    </div>

    @if (_allChannels.Count > 0)
    {
        <h5 class="mb-3">Muted Channels</h5>
        <div class="mb-4">
            @foreach (var channel in _allChannels)
            {
                <div class="form-check mb-2">
                    <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                           checked="@_mutedChannels.Contains(channel)"
                           @onchange="e => ToggleChannel(channel, (bool)(e.Value ?? false))" />
                    <label class="form-check-label" for="@($"ch-{channel}")">@channel</label>
                </div>
            }
        </div>
    }

    <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
        @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
        Save Preferences
    </button>
}

@code {
    private bool _loading = true;
    private bool _saving;
    private string? _successMessage;

    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private HashSet<string> _mutedChannels = new();
    private List<string> _allChannels = new();

    protected override async Task OnInitializedAsync()
    {
        var prefs = await SettingsService.GetNotificationPrefsAsync();
        _emailNotifications = prefs.EmailNotifications;
        _pushNotifications = prefs.PushNotifications;
        _weeklyDigest = prefs.WeeklyDigest;
        _allChannels = prefs.MutedChannels.ToList();
        _mutedChannels = prefs.MutedChannels.ToHashSet();
        _loading = false;
    }

    private void ToggleChannel(string channel, bool muted)
    {
        if (muted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _successMessage = null;
        var prefs = new NotificationPrefs(
            _emailNotifications, _pushNotifications, _weeklyDigest,
            _mutedChannels.ToList());
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _successMessage = "Notification preferences saved!";
        _saving = false;
    }
}

@namespace sv_7ab33c71045541e999d1f83ea1e56e67.Components.Pages.Settings
@using sv_7ab33c71045541e999d1f83ea1e56e67.Services
@inject ISettingsService SettingsService

<div class="card mb-4">
    <div class="card-header d-flex justify-content-between align-items-center"
         style="cursor:pointer" @onclick="() => _expanded = !_expanded">
        <span>🔑 Change Password</span>
        <span>@(_expanded ? "▲" : "▼")</span>
    </div>
    @if (_expanded)
    {
        <div class="card-body">
            @if (_errorMessage is not null)
            {
                <div class="alert alert-danger alert-dismissible fade show" role="alert">
                    @_errorMessage
                    <button type="button" class="btn-close" @onclick="() => _errorMessage = null"></button>
                </div>
            }
            @if (_successMessage is not null)
            {
                <div class="alert alert-success alert-dismissible fade show" role="alert">
                    @_successMessage
                    <button type="button" class="btn-close" @onclick="() => _successMessage = null"></button>
                </div>
            }

            <div class="mb-3">
                <label class="form-label">Current Password</label>
                <input type="password" class="form-control" @bind="_currentPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">New Password</label>
                <input type="password" class="form-control" @bind="_newPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control" @bind="_confirmPassword" />
            </div>
            <button class="btn btn-warning" @onclick="UpdatePasswordAsync" disabled="@_saving">
                @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                Update Password
            </button>
        </div>
    }
</div>

@code {
    private bool _expanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private bool _saving;
    private string? _errorMessage;
    private string? _successMessage;

    private async Task UpdatePasswordAsync()
    {
        _errorMessage = null;
        _successMessage = null;

        if (string.IsNullOrWhiteSpace(_currentPassword) ||
            string.IsNullOrWhiteSpace(_newPassword))
        {
            _errorMessage = "All password fields are required.";
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            _errorMessage = "New password and confirmation do not match.";
            return;
        }

        _saving = true;
        try
        {
            await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
            _successMessage = "Password updated successfully!";
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
        }
        catch (Exception ex)
        {
            _errorMessage = $"Failed to update password: {ex.Message}";
        }
        _saving = false;
    }
}

@namespace sv_7ab33c71045541e999d1f83ea1e56e67.Components.Pages.Settings
@using sv_7ab33c71045541e999d1f83ea1e56e67.Services

@if (Session is not null)
{
    <div class="modal fade show d-block" tabindex="-1" style="background-color:rgba(0,0,0,0.5);">
        <div class="modal-dialog modal-dialog-centered">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Revoke Session</h5>
                    <button type="button" class="btn-close" @onclick="Cancel"></button>
                </div>
                <div class="modal-body">
                    <p>Are you sure you want to revoke this session?</p>
                    <ul class="list-unstyled mb-0">
