    <div class="table-responsive">
        <table class="table table-striped align-middle">
            <thead>
                <tr>
                    <th>Device</th>
                    <th>Location</th>
                    <th>Last Active</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @foreach (var session in Sessions)
                {
                    <tr>
                        <td>@session.Device</td>
                        <td>@session.Location</td>
                        <td>@session.LastActive.ToString("g")</td>
                        <td>
                            @if (session.Id != CurrentSessionId)
                            {
                                <button class="btn btn-sm btn-outline-danger"
                                        @onclick="() => _sessionToRevoke = session">
                                    Revoke
                                </button>
                            }
                            else
                            {
                                <span class="badge bg-success">Current</span>
                            }
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}
else
{
    <p class="text-muted">No active sessions found.</p>
}

<RevokeSessionDialog Session="@_sessionToRevoke"
                     OnConfirmed="ConfirmRevoke"
                     OnCancelled="() => _sessionToRevoke = null" />

@code {
    [Parameter, EditorRequired] public List<ActiveSession>? Sessions { get; set; }
    [Parameter] public string? CurrentSessionId { get; set; }
    [Parameter, EditorRequired] public EventCallback<string> OnSessionRevoked { get; set; }

    private ActiveSession? _sessionToRevoke;

    private async Task ConfirmRevoke()
    {
        if (_sessionToRevoke is not null)
        {
            await OnSessionRevoked.InvokeAsync(_sessionToRevoke.Id);
            _sessionToRevoke = null;
        }
    }
}
"}

{"path": "/tmp/sv-7ab33c71045541e999d1f83ea1e56e67/Components/Pages/Settings/SecuritySection.razor", "file_text": "@namespace sv_7ab33c71045541e999d1f83ea1e56e67.Components.Pages.Settings
@using sv_7ab33c71045541e999d1f83ea1e56e67.Services
@inject ISettingsService SettingsService

@if (_loading)
{
    <div class="text-center py-5"><div class="spinner-border" role="status"></div></div>
}
else if (_settings is not null)
{
    <h4 class="mb-4">Security Settings</h4>

    <ChangePasswordPanel />

    <div class="card mb-4">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center">
                <div>
                    <h5 class="mb-1">Two-Factor Authentication</h5>
                    <span class="badge @(_settings.TwoFactorEnabled ? "bg-success" : "bg-secondary")">
                        @(_settings.TwoFactorEnabled ? "Enabled" : "Disabled")
                    </span>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="twoFactor"
                           checked="@_settings.TwoFactorEnabled" disabled
                           style="transform:scale(1.4);" />
                </div>
