"}

{"path": "/tmp/sv-7ab33c71045541e999d1f83ea1e56e67/Components/Pages/Settings/AppearanceSection.razor", "file_text": "@namespace sv_7ab33c71045541e999d1f83ea1e56e67.Components.Pages.Settings
@using sv_7ab33c71045541e999d1f83ea1e56e67.Services
@inject ISettingsService SettingsService

@if (_loading)
{
    <div class="text-center py-5"><div class="spinner-border" role="status"></div></div>
}
else
{
    <h4 class="mb-4">Appearance Settings</h4>

    @if (_successMessage is not null)
    {
        <div class="alert alert-success alert-dismissible fade show" role="alert">
            @_successMessage
            <button type="button" class="btn-close" @onclick="() => _successMessage = null"></button>
        </div>
    }

    <div class="row">
        <div class="col-md-6">
            <div class="mb-4">
                <h5>Theme</h5>
                @foreach (var theme in _themes)
                {
                    <div class="form-check">
                        <input class="form-check-input" type="radio" name="theme"
                               id="@($"theme-{theme}")" value="@theme"
                               checked="@(_theme == theme)"
                               @onchange="() => _theme = theme" />
                        <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                    </div>
                }
            </div>

            <div class="mb-4">
                <h5>Font Size</h5>
                @foreach (var size in _fontSizes)
                {
                    <div class="form-check">
                        <input class="form-check-input" type="radio" name="fontSize"
                               id="@($"fs-{size}")" value="@size"
                               checked="@(_fontSize == size)"
                               @onchange="() => _fontSize = size" />
                        <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                    </div>
                }
            </div>

            <div class="mb-4">
                <h5>Language</h5>
                <select class="form-select" @bind="_language">
                    @foreach (var lang in _languages)
                    {
                        <option value="@lang.Key">@lang.Value</option>
                    }
                </select>
            </div>

            <div class="mb-4">
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="compactMode" @bind="_compactMode" />
                    <label class="form-check-label" for="compactMode">Compact Mode</label>
                </div>
            </div>

            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                Save
            </button>
        </div>

        <div class="col-md-6">
            <h5>Live Preview</h5>
            <div class="border rounded p-3 @PreviewBackgroundClass" style="@PreviewStyle">
                <h6 style="@PreviewFontStyle">Sample Heading</h6>
                <p style="@PreviewFontStyle" class="@(PreviewTextClass) mb-2">
                    This is how your content will look with the selected settings.
                </p>
                <div class="d-flex gap-2 @(_compactMode ? "mb-1" : "mb-3")">
                    <span class="badge bg-primary">Tag 1</span>
                    <span class="badge bg-secondary">Tag 2</span>
                    <span class="badge bg-info">Tag 3</span>
                </div>
                <button class="btn btn-sm btn-primary">Sample Button</button>
            </div>
        </div>
    </div>
}

@code {
    private bool _loading = true;
    private bool _saving;
    private string? _successMessage;

    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "en";
    private bool _compactMode;

    private static readonly string[] _themes = ["Light", "Dark", "System"];
    private static readonly string[] _fontSizes = ["Small", "Medium", "Large"];
    private static readonly Dictionary<string, string> _languages = new()
    {
        ["en"] = "English",
        ["es"] = "Español",
        ["fr"] = "Français",
        ["de"] = "Deutsch",
        ["ja"] = "日本語"
    };

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetAppearanceAsync();
        _theme = settings.Theme;
        _fontSize = settings.FontSize;
        _language = settings.Language;
        _compactMode = settings.CompactMode;
        _loading = false;
    }

    private string PreviewBackgroundClass => _theme switch
    {
        "Dark" => "bg-dark text-light",
        _ => "bg-light text-dark"
    };

    private string PreviewTextClass => _theme switch
    {
        "Dark" => "text-light",
        _ => "text-dark"
    };

    private string PreviewStyle => _theme == "Dark"
        ? "min-height:180px; border-color:#495057 !important;"
        : "min-height:180px;";

    private string PreviewFontStyle => _fontSize switch
    {
        "Small" => "font-size:0.85rem;",
        "Large" => "font-size:1.25rem;",
        _ => "font-size:1rem;"
    };

    private async Task SaveAsync()
    {
        _saving = true;
        _successMessage = null;
        await SettingsService.SaveAppearanceAsync(
            new AppearanceSettings(_theme, _fontSize, _language, _compactMode));
        _successMessage = "Appearance settings saved!";
        _saving = false;
    }
}
"}

