@namespace sv_7ab33c71045541e999d1f83ea1e56e67.Components.Pages.Settings
@using sv_7ab33c71045541e999d1f83ea1e56e67.Services

@if (Session is not null)
{
    <div class="modal fade show d-block" tabindex="-1" style="background-color:rgba(0,0,0,0.5);">
        <div class="modal-dialog modal-dialog-centered">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Revoke Session</h5>
                    <button type="button" class="btn-close" @onclick="Cancel"></button>
                </div>
                <div class="modal-body">
                    <p>Are you sure you want to revoke this session?</p>
                    <ul class="list-unstyled mb-0">
                        <li><strong>Device:</strong> @Session.Device</li>
                        <li><strong>Location:</strong> @Session.Location</li>
                        <li><strong>Last Active:</strong> @Session.LastActive.ToString("g")</li>
                    </ul>
                </div>
                <div class="modal-footer">
                    <button class="btn btn-secondary" @onclick="Cancel">Cancel</button>
                    <button class="btn btn-danger" @onclick="Confirm">Revoke Session</button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter, EditorRequired] public ActiveSession? Session { get; set; }
    [Parameter, EditorRequired] public EventCallback OnConfirmed { get; set; }
    [Parameter, EditorRequired] public EventCallback OnCancelled { get; set; }

    private async Task Confirm() => await OnConfirmed.InvokeAsync();
    private async Task Cancel() => await OnCancelled.InvokeAsync();
}

@namespace sv_7ab33c71045541e999d1f83ea1e56e67.Components.Pages.Settings
@using sv_7ab33c71045541e999d1f83ea1e56e67.Services

<h5 class="mb-3">Active Sessions</h5>

@if (Sessions is not null && Sessions.Count > 0)
{
    <div class="table-responsive">
        <table class="table table-striped align-middle">
            <thead>
                <tr>
                    <th>Device</th>
                    <th>Location</th>
                    <th>Last Active</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @foreach (var session in Sessions)
                {
                    <tr>
                        <td>@session.Device</td>
                        <td>@session.Location</td>
                        <td>@session.LastActive.ToString("g")</td>
                        <td>
                            @if (session.Id != CurrentSessionId)
                            {
                                <button class="btn btn-sm btn-outline-danger"
                                        @onclick="() => _sessionToRevoke = session">
                                    Revoke
                                </button>
                            }
                            else
                            {
                                <span class="badge bg-success">Current</span>
                            }
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}
else
{
    <p class="text-muted">No active sessions found.</p>
}

<RevokeSessionDialog Session="@_sessionToRevoke"
                     OnConfirmed="ConfirmRevoke"
                     OnCancelled="() => _sessionToRevoke = null" />

@code {
    [Parameter, EditorRequired] public List<ActiveSession>? Sessions { get; set; }
    [Parameter] public string? CurrentSessionId { get; set; }
    [Parameter, EditorRequired] public EventCallback<string> OnSessionRevoked { get; set; }

    private ActiveSession? _sessionToRevoke;

    private async Task ConfirmRevoke()
    {
        if (_sessionToRevoke is not null)
        {
            await OnSessionRevoked.InvokeAsync(_sessionToRevoke.Id);
            _sessionToRevoke = null;
        }
    }
}

@namespace sv_7ab33c71045541e999d1f83ea1e56e67.Components.Pages.Settings
@using sv_7ab33c71045541e999d1f83ea1e56e67.Services
@inject ISettingsService SettingsService

@if (_loading)
{
    <div class="text-center py-5"><div class="spinner-border" role="status"></div></div>
}
else if (_settings is not null)
{
    <h4 class="mb-4">Security Settings</h4>

    <ChangePasswordPanel />

    <div class="card mb-4">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center">
                <div>
                    <h5 class="mb-1">Two-Factor Authentication</h5>
                    <span class="badge @(_settings.TwoFactorEnabled ? "bg-success" : "bg-secondary")">
                        @(_settings.TwoFactorEnabled ? "Enabled" : "Disabled")
                    </span>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="twoFactor"
                           checked="@_settings.TwoFactorEnabled" disabled
                           style="transform:scale(1.4);" />
                </div>
            </div>
            @if (_settings.LastPasswordChange.HasValue)
            {
                <small class="text-muted d-block mt-2">
                    Last password change: @_settings.LastPasswordChange.Value.ToString("f")
                </small>
            }
        </div>
    </div>

    <ActiveSessionsTable Sessions="@_settings.Sessions"
                         CurrentSessionId="@_settings.Sessions.FirstOrDefault()?.Id"
                         OnSessionRevoked="RevokeSessionAsync" />
}

@code {
    private SecuritySettings? _settings;
    private bool _loading = true;

    protected override async Task OnInitializedAsync()
    {
        await LoadAsync();
    }

    private async Task LoadAsync()
    {
        _loading = true;
        _settings = await SettingsService.GetSecuritySettingsAsync();
        _loading = false;
    }

    private async Task RevokeSessionAsync(string sessionId)
    {
        await SettingsService.RevokeSessionAsync(sessionId);
        await LoadAsync();
    }
}

